package health.ere.ps.resource.xml;

import health.ere.ps.profile.RUTestProfile;
import health.ere.ps.resource.gematik.UpdateERezept;
import health.ere.ps.service.gematik.ERezeptWorkflowService;
import io.quarkus.test.junit.QuarkusMock;
import io.quarkus.test.junit.QuarkusTest;
import io.quarkus.test.junit.TestProfile;
import jakarta.enterprise.event.Event;
import jakarta.inject.Inject;
import jakarta.ws.rs.WebApplicationException;
import jakarta.ws.rs.core.Response;
import org.junit.jupiter.api.Disabled;
import org.junit.jupiter.api.Test;
import org.mockito.AdditionalMatchers;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.Base64;

import static io.restassured.RestAssured.given;
import static jakarta.ws.rs.core.HttpHeaders.ACCEPT;
import static jakarta.ws.rs.core.HttpHeaders.CONTENT_TYPE;
import static jakarta.ws.rs.core.MediaType.APPLICATION_JSON;
import static jakarta.ws.rs.core.MediaType.APPLICATION_XML;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.mockito.ArgumentMatchers.anyBoolean;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.isNull;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.mock;

@QuarkusTest
@TestProfile(RUTestProfile.class)
public class XmlPrescriptionResourceTest {

    @Inject
    ERezeptWorkflowService eRezeptWorkflowService;

    @Test
    public void webExceptionTest() {
        String base64Bytes = "";

        Response.ResponseBuilder responseBuilder = Response.status(400);
        responseBuilder.entity("<?xml version=\"1.0\" encoding=\"utf-8\"?><OperationOutcome xmlns=\"http://hl7.org/fhir\"><meta><profile value=\"http://hl7.org/fhir/StructureDefinition/OperationOutcome\"/></meta><issue><severity value=\"error\"/><code value=\"invalid\"/><details><text value=\"Ungültige Versichertennummer (KVNR): Die übergebene Versichertennummer des Patienten entspricht nicht den Prüfziffer-Validierungsregeln.\"/></details></issue></OperationOutcome>");
        Response responseError = responseBuilder.build();

        ERezeptWorkflowService service = mock(ERezeptWorkflowService.class);
        byte[] array = Base64.getDecoder().decode(base64Bytes);
        doThrow(new WebApplicationException(responseError)).when(service).updateERezeptTask(
            anyString(),
            anyString(),
            AdditionalMatchers.aryEq(array),
            anyBoolean(),
            isNull(),
            isNull(),
            isNull()
        );
        QuarkusMock.installMockForType(service, ERezeptWorkflowService.class);

        UpdateERezept updateERezept = new UpdateERezept();
        updateERezept.setAccessCode("accessCode");
        updateERezept.setSignedBytes(base64Bytes);
        updateERezept.setTaskId("taskId");
        io.restassured.response.Response response = given()
            .header(ACCEPT, APPLICATION_XML)
            .contentType(APPLICATION_JSON)
            .body(updateERezept)
            .when()
            .post("/workflow/update");
        assertEquals(400, response.getStatusCode());
        assertTrue(response.getHeader(CONTENT_TYPE).contains("application/xml"));

        String xmlBody = response.asString();
        assertTrue(xmlBody.contains("<issue>"));
        assertTrue(xmlBody.contains("Ungültige Versichertennummer"));

        QuarkusMock.installMockForType(eRezeptWorkflowService, ERezeptWorkflowService.class);
    }

    @Test
    @Disabled
    public void testPost() throws IOException {
        XmlPrescriptionResource xmlPrescriptionResource = new XmlPrescriptionResource();
        xmlPrescriptionResource.bundleEvent = mock(Event.class);
        xmlPrescriptionResource.post(new String(Files.readAllBytes(Paths.get("/home/manuel/git/secret-test-print-samples/CGM-Turbomed/XML/Kaiser_Bella_20210630113252.xml"))));
    }
}
